input.new_string:
addASSPerson(nickName) {
    if (!nickName) return
    // 按空格、中文逗号、英文逗号、顿号拆分，过滤空值
    const names = nickName.split(/[\s,，、]+/).filter(Boolean)
    const existingLabels = new Set(this.editDia.bindData.ASSPerson.map(o => o.label))
    const duplicates: string[] = []
    const added: string[] = []
    for (const name of names) {
        if (existingLabels.has(name)) {
            duplicates.push(name)
        } else {
            existingLabels.add(name)
            this.editDia.bindData.ASSPerson.push({ value: name, label: name })
            added.push(name)
        }
    }
    if (duplicates.length > 0) {
        this.$message.warning(`已存在：${duplicates.join('、')}`)
    }
    this.editDia.inputValue = ''
    this.editForm.clearValidate()
}

