import dayjs from 'dayjs'
import {toNumber} from 'lodash'

import {getDeptMapAPI} from '@/apis/DeptManagement'
import {getEmailConfigAPI} from '@/apis/ResignManagement'
import {forceUpdateStaffSfUserAllResAttrAPI} from '@/apis/StaffManagement'
import axios2 from '@/apis/axios2'
import {getUserByNickName} from '@/apis/common'
import {isOtherType} from '@/apis/constant'
import {ajaxUrl} from '@/appConstant'
import i18n from '@/i18n'

// AI 日报邮件固定额外收件人 ID
const AI_EMAIL_EXTRA_RECIPIENT_ID = BRANCH_NAME === 'master' ? 171514 : 232753

export type DeptDataT = {
    id: number
    name: string
    sscName: string
    creator: string
    createTime: string
    updateTime: string
    status: boolean
}

export const defaultDeptData: DeptDataT = {
    id: 0,
    name: '',
    status: true,
    sscName: '',
    updateTime: '',
    creator: '',
    createTime: '',
}

export const getDeptListAPI = (): Promise<DeptDataT[]> =>
    new Promise((resolve, reject) => {
        axios2(`${ajaxUrl.WebAPI}configuration-management`, 'post', {}, 'auto')
            .then(r => {
                resolve(
                    r.departments.map((o): DeptDataT => {
                        return {
                            id: o.department_id,
                            name: o.department_name,
                            createTime: dayjs(toNumber(o.created_at) * 1000).format('YYYY-MM-DD hh:mm:ss'),
                            creator: o.creator_id,
                            sscName: o.ssc_id,
                            updateTime: dayjs(toNumber(o.updated_at) * 1000).format('YYYY-MM-DD hh:mm:ss'),
                            status: !!o.is_on,
                        }
                    })
                )
            })
            .catch(e => {
                console.error(e)
                reject(e)
            })
    })

export const addDeptAPI = (param: DeptDataT) =>
    axios2(
        `${ajaxUrl.WebAPI}jobs/add-department`,
        'post',
        {
            department_name: param.name,
            ssc_id: param.sscName,
        },
        'auto'
    )

export const updateDeptAPI = (param: Partial<DeptDataT>, status = true) =>
    axios2(
        `${ajaxUrl.WebAPI}jobs/update-department`,
        'post',
        {
            department_id: param.id,
            department_name: param.name,
            ssc_id: param.sscName,
            is_on: toNumber(status),
        },
        'auto'
    )

export type APCDataT = {
    // 唯一标识
    id: string
    // 配置项唯一标识
    configItem: string
    // 配置项名称
    configItemLabel: string
    // 关联人员 value：关联人唯一标识 label：关联人花名
    ASSPerson: { value: string; label: string }[]
    // 是否可以绑定多人，这将影响到编辑窗口的展示
    multiple: boolean
    // 数据是否异常，异常数据会提示，并且相关数据为空，方便用户进行修改
    abnormal: boolean
    group: {
        // 花名 作为唯一标识
        nickName: string
        deptList: { label: string; value: number }[]
    }[]
}

export const getAPCListAPI = (): Promise<{ data: APCDataT[]; total: number }> =>
    new Promise((resolve, reject) => {
        Promise.all([
            getDeptMapAPI(true),
            axios2(`${ajaxUrl.WebAPI}hr-approval/get-special-nickname`, 'post', {}),
        ])
            .then(([maps, r]) => {
                resolve({
                    data: r.special_nicknames.map(o => {
                        let abnormal = true
                        let ASSPerson = []
                        // 判断数据是否异常
                        if (o.nicknames.length === o.ids.length) {
                            abnormal = false
                            ASSPerson = o.nicknames.map(o => ({
                                label: o,
                                value: o,
                            }))
                        }
                        const item: APCDataT = {
                            id: o.type,
                            configItem: o.kind,
                            configItemLabel: o.name,
                            abnormal,
                            multiple: o.kind === 'cc',
                            ASSPerson,
                            group: o.special_config.map((oo): APCDataT['group'][0] => ({
                                nickName: oo.nicknames[0] || '-',
                                deptList: oo.department_ids.map(ooo => ({
                                    value: ooo,
                                    label: maps.getDeptById(ooo)?.name || '-',
                                })),
                            })),
                        }

                        return item
                    }),
                    total: r.special_nicknames.length,
                })
            })
            .catch(e => {
                console.error('getAPCListAPI error', e)
                reject(e)
            })
    })
export const editAPCDataAPI = (param: APCDataT) =>
    new Promise((resolve, reject) => {
        const nicknames = param.ASSPerson.map(o => o.label)
        getUserByNickName([...param.ASSPerson.map(o => o.label), ...param.group.map(o => o.nickName)])
            .then(userMap => {
                const sfuser_ids = param.ASSPerson.map(o => userMap.getByName(o.label).sfUserId)
                axios2(`${ajaxUrl.WebAPI}hr-approval/edit-special-nickname`, 'post', {
                    // hash_filter: {
                    //     obj: '$this',
                    //     columns: ['nicknames', 'special_config.*.nicknames'],
                    // },
                    // decrypt_config: {
                    //     obj: 'special_nickname',
                    //     decrypt_columns: ['ids_mapped_nicknames'],
                    // },
                    intact_columns: ['type', 'nicknames_plaintext', 'special_config', 'sfuser_ids'],
                    type: param.id,
                    sfuser_ids: sfuser_ids,
                    // nicknames,
                    nicknames_plaintext: nicknames,
                    special_config: param.group.map(o => ({
                        // nicknames: [o.nickName],
                        sfuser_ids: [userMap.getByName(o.nickName).sfUserId],
                        nicknames_plaintext: [o.nickName],
                        department_ids: o.deptList.map(o => o.value),
                    })),
                })
                    .then(r => {
                        if (isOtherType(param.id)) {
                            sfuser_ids.forEach(sfuser_id => {
                                forceUpdateStaffSfUserAllResAttrAPI(sfuser_id,userMap.getBySfUserId(sfuser_id).nickName).then(r => r)
                            })
                        }
                        resolve(r)
                    })
                    .catch(e => {
                        console.error('editAPCDataAPI error', e)
                        reject(e.error_msg ||<string>i18n.t('serverException'))
                    })
            })
            .catch(e => {
                reject(e)
            })
    })

export const getOASettingListAPI = (): Promise<{ data: APCDataT[]; total: number }> =>
    new Promise((resolve, reject) => {
        Promise.all([
            getDeptMapAPI(true),
            axios2(`${ajaxUrl.WebAPI}hr-approval/get-oa-setting`, 'post', {}),
        ])
            .then(([maps, r]) => {
                resolve({
                    data: r.special_nicknames.map(o => {
                        let abnormal = true
                        let ASSPerson = []
                        // 判断数据是否异常
                        if (o.nicknames.length === o.ids.length) {
                            abnormal = false
                            ASSPerson = o.nicknames.map(o => ({
                                label: o,
                                value: o,
                            }))
                        }
                        // daily_report_ai 的 special_config 格式为 [{sfuser_id, email}]，无需解析 group
                        const isDailyReportAi = o.type === 'daily_report_ai'
                        const item: APCDataT = {
                            id: o.type,
                            configItem: o.kind,
                            configItemLabel: o.name,
                            abnormal,
                            multiple: true,
                            ASSPerson,
                            group: isDailyReportAi
                                ? []
                                : o.special_config.map((oo): APCDataT['group'][0] => ({
                                      nickName: oo.nicknames[0] || '-',
                                      deptList: (oo.department_ids || []).map(ooo => ({
                                          value: ooo,
                                          label: maps.getDeptById(ooo)?.name || '-',
                                      })),
                                  })),
                        }

                        return item
                    }),
                    total: r.special_nicknames.length,
                })
            })
            .catch(e => {
                console.error('getAPCListAPI error', e)
                reject(e)
            })
    })
export const editOaSettingDataAPI = (param: APCDataT) =>
    new Promise((resolve, reject) => {
        const nicknames = param.ASSPerson.map(o => o.label)
        getUserByNickName([...param.ASSPerson.map(o => o.label), ...param.group.map(o => o.nickName)])
            .then(userMap => {
                const sfuser_ids = param.ASSPerson.map(o => userMap.getByName(o.label)?.sfUserId)

                // daily_report_ai：通过 staff 接口查白名单用户解密邮箱 + EXTRA_RECIPIENT 邮箱，生成 token
                if (param.id === 'daily_report_ai') {
                    // 通过 web-api/staff 接口 + hash_filter 查解密后的 email（不依赖 getUserByNickName 缓存）
                    const validSfuserIds = sfuser_ids.filter(Boolean)
                    Promise.all([
                        axios2(`${ajaxUrl.WebAPI}staff`, 'post', {
                            intact_columns: ['nicknames'],
                            hash_filter: {
                                obj: '$this',
                                columns: ['nicknames'],
                            },
                            nicknames,
                            per_page: nicknames.length || 1,
                            decrypt_config: {
                                obj: 'sfusers.*',
                                decrypt_columns: ['nickname', 'email'],
                            },
                        }),
                        getEmailConfigAPI(`daily_report_${AI_EMAIL_EXTRA_RECIPIENT_ID}`),
                    ])
                        .then(([staffRes, emailConfig]: [any, any]) => {
                            // 从 staff 接口响应中提取 sfuser_id → email 映射
                            const staffList: any[] = staffRes?.sfusers || []
                            const whitelistEmailConfigs = staffList
                                .filter(s => s.id && s.email)
                                .map(s => ({sfuser_id: s.id, email: s.email}))

                            const extraEmails: string[] = emailConfig?.data?.[0]?.email || []
                            const whitelistEmails = whitelistEmailConfigs.map(o => o.email)
                            const allEmails = [...new Set([...extraEmails, ...whitelistEmails])]

                            console.info('[lbl][0422-AI日报邮件][OaSetting][UPDATE] 保存白名单配置', {
                                sfuser_ids: validSfuserIds,
                                whitelistCount: whitelistEmailConfigs.length,
                                allEmailCount: allEmails.length,
                            })
                            axios2(`${ajaxUrl.WebAPI}hr-approval/edit-oa-setting`, 'post', {
                                intact_columns: ['type', 'nicknames_plaintext', 'special_config', 'sfuser_ids', 'ai_email_all_emails'],
                                type: param.id,
                                sfuser_ids,
                                nicknames_plaintext: nicknames,
                                // special_config 存白名单用户的 sfuser_id + 明文邮箱
                                special_config: whitelistEmailConfigs,
                                // 所有邮箱（EXTRA_RECIPIENT + 白名单），用于 authorize_config 生成 token
                                ai_email_all_emails: allEmails,
                                // authorize_config 让 oa-core 生成包含所有邮箱的 token
                                authorize_config: {
                                    res_type: 'sfuser',
                                    sfusers: [],
                                    emails: allEmails,
                                    items: 'all',
                                    operations: ['send_email'],
                                    expire_time: 4294967295,
                                },
                            })
                                .then(r => resolve(r))
                                .catch(e => {
                                    console.error('editOaSettingDataAPI error', e)
                                    reject(e.error_msg || <string>i18n.t('serverException'))
                                })
                        })
                        .catch(e => {
